        CSVRecord result = null;
        record.clear();
        StringBuilder sb = null;
        do {
            reusableToken.reset();
            lexer.nextToken(reusableToken);
            switch (reusableToken.type) {
            case TOKEN:
                record.add(reusableToken.content.toString());
                break;
            case EORECORD:
                record.add(reusableToken.content.toString());
                break;
            case EOF:
