                    record.add(reusableToken.content.toString());
                }
                break;
            case INVALID:
                throw new IOException("(line " + getLineNumber() + ") invalid parse sequence");
            case COMMENT: // Ignored currently
                if (sb == null) { // first comment for this record
                    sb = new StringBuilder();
                } else {
                    sb.append("\n");
