import org.apache.commons.csv.CSVParser;
import org.apache.commons.csv.CSVRecord;
import org.junit.Assert;

import java.io.IOException;
import java.io.StringReader;
import java.util.List;

public class StepDefs {

    private CSVFormat format;
    private String input;
    private List<String> tokens;
    private Exception exception;

    @Given("I have a CSV lexer configured with escape character {string}")
    public void given_i_have_a_CSV_lexer_configured_with_escape_character(String escapeChar) {
        char esc = escapeChar.charAt(0);
        this.format = CSVFormat.newBuilder().withEscape(esc).withIgnoreSurroundingSpaces(false).build();
    }

    @When("I tokenize the input string {string}")
    public void when_i_tokenize_the_input_string(String inputStr) {
        this.input = inputStr;
        this.exception = null;
        try {
            // Use CSVParser to parse the input string which will use the lexer internally
            CSVParser parser = new CSVParser(inputStr, this.format);
            List<CSVRecord> records = parser.getRecords();
            if (!records.isEmpty()) {
                this.tokens = records.get(0).getRecordList();
            } else {
                // If no records, create an empty token list
                this.tokens = java.util.Arrays.asList(inputStr);
            }
        } catch (IOException e) {
            this.exception = e;
        } catch (Exception e) {
            this.exception = e;
        }
    }

    @Then("the generated token content should be {string}")
    public void then_the_generated_token_content_should_be(String expected) {
        if (exception != null) {
            Assert.fail("Exception occurred: " + exception.getMessage());
        }
        Assert.assertNotNull("Tokens list should not be null", tokens);
        Assert.assertTrue("Tokens list should not be empty", !tokens.isEmpty());
        Assert.assertEquals(expected, tokens.get(0));
    }
}

